"use client";

import {
  type AvatarProps,
  Avatar as AvatarRoot,
  type AvatarStatus,
  avatarVariants,
} from "./avatar";
import { AvatarFallback, type AvatarFallbackProps } from "./avatar-fallback";
import { AvatarGroup, type AvatarGroupProps, avatarGroupSpacingVariants } from "./avatar-group";
import { AvatarImage, type AvatarImageProps } from "./avatar-image";
import { AvatarIndicator, type AvatarIndicatorProps } from "./avatar-indicator";

const Avatar = Object.assign(AvatarRoot, {
  Image: AvatarImage,
  Fallback: AvatarFallback,
  Group: AvatarGroup,
  Indicator: AvatarIndicator,
});

export { Avatar, avatarVariants, type AvatarProps, type AvatarStatus };
export { AvatarImage, type AvatarImageProps };
export { AvatarFallback, type AvatarFallbackProps };
export { AvatarGroup, avatarGroupSpacingVariants, type AvatarGroupProps };
export { AvatarIndicator, type AvatarIndicatorProps };

"use client";

import { createContext, useContext } from "react";

/** Allowed avatar status values. */
export type AvatarStatus = "idle" | "loading" | "loaded" | "error";

/** Context value shared by avatar group. */
export interface AvatarGroupContextValue {
  /** Default size applied to descendant Avatars that do not set their own size. */
  size?: "sm" | "md" | "lg" | null;
}

/** React context backing avatar group. */
export const AvatarGroupContext = createContext<AvatarGroupContextValue | undefined>(undefined);

/** Reads the avatar group context. */
export function useAvatarGroupContext() {
  return useContext(AvatarGroupContext);
}

/** Context value shared by avatar. */
export interface AvatarContextValue {
  imageStatus: AvatarStatus;
  /** Updates image status. */
  setImageStatus: (status: AvatarStatus) => void;
}

/** React context backing avatar. */
export const AvatarContext = createContext<AvatarContextValue | undefined>(undefined);

/** Reads the avatar context. */
export function useAvatarContext() {
  const ctx = useContext(AvatarContext);
  if (!ctx) {
    throw new Error("Avatar.Image and Avatar.Fallback must be used within Avatar");
  }
  return ctx;
}

"use client";

import { cva, type VariantProps } from "class-variance-authority";
import {
  type ComponentProps,
  type ReactNode,
  useEffect,
  useEffectEvent,
  useMemo,
  useState,
} from "react";
import { cn } from "@/lib/utils";
import { AvatarContext, type AvatarStatus, useAvatarGroupContext } from "./avatar-context";
import { AvatarFallback } from "./avatar-fallback";
import { AvatarImage } from "./avatar-image";

export type { AvatarStatus };

export const avatarVariants = cva(
  "relative inline-flex items-center justify-center border border-foreground/40 font-mono font-medium text-foreground bg-background overflow-hidden shrink-0",
  {
    variants: {
      size: {
        sm: "size-6 text-2xs",
        md: "size-8 text-xs",
        lg: "size-10 text-sm",
      },
    },
    defaultVariants: { size: "md" },
  },
);

export interface AvatarProps extends ComponentProps<"span">, VariantProps<typeof avatarVariants> {
  /** Image URL. Ignored when children are provided. */
  src?: string;
  /**
   * Image alt text and accessible name. When omitted, falls back to a string `fallback`. When
   * neither is set, the avatar uses role="presentation".
   */
  alt?: string;
  /** Shown when the image is loading, missing, or fails. */
  fallback?: ReactNode;
  /** Fired when the image load status changes. Fires for the active image only. */
  onStatusChange?: (status: AvatarStatus) => void;
  /** Custom inner content. Replaces the default AvatarImage + AvatarFallback composition. */
  children?: ReactNode;
}

/** Square avatar with src/fallback/size. Shows image or monospace initials. */
function AvatarRoot({
  src,
  alt,
  fallback,
  size,
  className,
  ref,
  onStatusChange,
  children,
  ...props
}: AvatarProps) {
  const groupCtx = useAvatarGroupContext();
  const resolvedSize = size ?? groupCtx?.size;
  const [imageStatus, setImageStatus] = useState<AvatarStatus>("idle");
  const notifyStatusChange = useEffectEvent((status: AvatarStatus) => {
    onStatusChange?.(status);
  });

  useEffect(() => {
    if (imageStatus === "idle") return;
    notifyStatusChange(imageStatus);
  }, [imageStatus]);

  const contextValue = useMemo(() => ({ imageStatus, setImageStatus }), [imageStatus]);

  const label = alt ?? (typeof fallback === "string" ? fallback : undefined);

  return (
    <AvatarContext value={contextValue}>
      {/* biome-ignore lint/a11y/useAriaPropsSupportedByRole: role is conditionally "img" (Biome cannot resolve the ternary); aria-label is set in the same branch and is valid for the img role. */}
      <span
        ref={ref}
        role={label ? "img" : "presentation"}
        data-slot="avatar"
        aria-label={label || undefined}
        className={cn(avatarVariants({ size: resolvedSize }), className)}
        {...props}
      >
        {children ?? (
          <>
            {src && <AvatarImage src={src} />}
            <AvatarFallback>{fallback ?? "?"}</AvatarFallback>
          </>
        )}
      </span>
    </AvatarContext>
  );
}

export { AvatarRoot as Avatar };

"use client";

import { type ImgHTMLAttributes, type Ref, useEffect, useEffectEvent } from "react";
import { cn } from "@/lib/utils";
import { useAvatarContext } from "./avatar-context";
import { useImageStatus } from "./use-image-status";

/** Props for avatar image. */
export interface AvatarImageProps extends Omit<ImgHTMLAttributes<HTMLImageElement>, "alt"> {
  /**
   * Accessible name for the image. Defaults to `""`, treating the avatar as decorative so it is
   * skipped by assistive tech and the surrounding control (button, link, card) supplies the
   * accessible name. Pass an explicit `alt` when the avatar is the sole label for its
   * container.
   */
  alt?: string;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLImageElement>;
}

export function AvatarImage({ src, alt, className, ref, ...imgProps }: AvatarImageProps) {
  const { setImageStatus } = useAvatarContext();
  const { showImage, onLoad, onError } = useImageStatus(src);
  const notifyStatus = useEffectEvent(setImageStatus);

  // Lifecycle sync only: the presence/absence of `src` decides the initial
  // loading/idle status, and unmount/src-change resets to idle. Load/error
  // transitions are notified directly from the event handlers below.
  useEffect(() => {
    notifyStatus(src ? "loading" : "idle");
    return () => notifyStatus("idle");
  }, [src]);

  if (!showImage) return null;

  return (
    <img
      ref={ref}
      src={src}
      alt={alt ?? ""}
      className={cn("absolute inset-0 size-full object-cover", className)}
      {...imgProps}
      onLoad={(event) => {
        onLoad();
        setImageStatus("loaded");
        imgProps.onLoad?.(event);
      }}
      onError={(event) => {
        onError();
        setImageStatus("error");
        imgProps.onError?.(event);
      }}
    />
  );
}

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useAvatarContext } from "./avatar-context";
import { useImageStatus } from "./use-image-status";

/** Props for avatar fallback. */
export interface AvatarFallbackProps {
  /** Cascading fallback image. Tried before rendering children. */
  src?: string;
  /** Initials or icon shown when no fallback image is available. */
  children?: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
}

export function AvatarFallback({ src, children, className }: AvatarFallbackProps) {
  const { imageStatus } = useAvatarContext();
  const fallbackImage = useImageStatus(src);

  if (imageStatus === "loaded") return null;
  if (src && fallbackImage.showImage) {
    return (
      <img
        src={src}
        alt=""
        onLoad={fallbackImage.onLoad}
        onError={fallbackImage.onError}
        className={cn("absolute inset-0 size-full object-cover", className)}
      />
    );
  }

  return <span className={className}>{children}</span>;
}

"use client";

import type { VariantProps } from "class-variance-authority";
import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";
import { avatarVariants } from "./avatar";
import { useAvatarGroupContext } from "./avatar-context";

/** Props for avatar indicator. */
export interface AvatarIndicatorProps
  extends Omit<ComponentProps<"span">, "role">,
    VariantProps<typeof avatarVariants> {
  /** Number rendered as "+N". Used by AvatarGroup for overflow but available standalone. */
  count: number;
  /** Accessible name for the "+N" overflow indicator. Defaults to `${count} more`. */
  getLabel?: (count: number) => string;
}

/** Overflow count badge (+N). Auto-rendered by AvatarGroup, or usable standalone. */
export function AvatarIndicator({
  count,
  size,
  className,
  "aria-label": ariaLabel,
  getLabel,
  ...props
}: AvatarIndicatorProps) {
  const groupCtx = useAvatarGroupContext();
  const resolvedSize = size ?? groupCtx?.size;
  return (
    <span
      {...props}
      role="img"
      aria-label={ariaLabel ?? getLabel?.(count) ?? `${count} more`}
      className={cn(
        avatarVariants({ size: resolvedSize }),
        "border-dashed bg-muted text-foreground",
        className,
      )}
    >
      <span aria-hidden="true">+{count}</span>
    </span>
  );
}

"use client";

import { cva, type VariantProps } from "class-variance-authority";
import { Children, type ComponentProps, useMemo } from "react";
import { cn } from "@/lib/utils";
import { Overflow } from "../overflow/overflow";
import { AvatarGroupContext } from "./avatar-context";
import { AvatarIndicator } from "./avatar-indicator";

/** Class variants for avatar group spacing. */
export const avatarGroupSpacingVariants = cva("", {
  variants: {
    spacing: {
      overlap: "-space-x-1.5",
      gap: "gap-1",
    },
  },
  defaultVariants: { spacing: "overlap" },
});

/** Props for avatar group. */
export interface AvatarGroupProps extends Omit<ComponentProps<"div">, "role"> {
  /**
   * Hard cap on visible avatars. Extras render as an AvatarIndicator. When omitted, AvatarGroup
   * measures overflow with Overflow. Values are rounded down; negative and non-finite values
   * become zero.
   */
  max?: number;
  /** Overlap stacks avatars; gap spaces them apart. */
  spacing?: NonNullable<VariantProps<typeof avatarGroupSpacingVariants>["spacing"]>;
  /** Default size applied to descendant Avatars that do not set their own size. */
  size?: "sm" | "md" | "lg" | null;
}

/** Overlapping stack of avatars with max overflow (+N indicator). */
export function AvatarGroup({
  max,
  spacing = "overlap",
  children,
  size = "md",
  className,
  "aria-label": ariaLabel = "Avatars",
  ...props
}: AvatarGroupProps) {
  const allItems = Children.toArray(children);
  const groupContextValue = useMemo(() => ({ size }), [size]);

  if (max != null) {
    const normalizedMax = Number.isFinite(max) ? Math.max(0, Math.floor(max)) : 0;
    const visibleItems = allItems.slice(0, normalizedMax);
    const overflowCount = allItems.length - visibleItems.length;

    return (
      <AvatarGroupContext value={groupContextValue}>
        {/* biome-ignore lint/a11y/useSemanticElements: role="group" labels the related set of avatars; <fieldset> is for form controls and is not appropriate here. */}
        <div
          {...props}
          role="group"
          aria-label={ariaLabel}
          className={cn(
            "flex w-fit items-center",
            avatarGroupSpacingVariants({ spacing }),
            className,
          )}
        >
          {visibleItems}
          {overflowCount > 0 && <AvatarIndicator count={overflowCount} />}
        </div>
      </AvatarGroupContext>
    );
  }

  return (
    <AvatarGroupContext value={groupContextValue}>
      {/* biome-ignore lint/a11y/useSemanticElements: role="group" labels the related set of avatars; <fieldset> is for form controls and is not appropriate here. */}
      <div {...props} role="group" aria-label={ariaLabel}>
        <Overflow
          mode="items"
          gap={avatarGroupSpacingVariants({ spacing })}
          className={className}
          indicator={({ count }) => <AvatarIndicator count={count} />}
        >
          {allItems}
        </Overflow>
      </div>
    </AvatarGroupContext>
  );
}

"use client";
import { useEffect, useState } from "react";
import type { AvatarStatus } from "./avatar-context";

interface ImageStatusState {
  src: string | undefined;
  status: AvatarStatus;
}

export function useImageStatus(src: string | undefined) {
  const [state, setState] = useState<ImageStatusState>(() => ({
    src,
    status: src ? "loading" : "idle",
  }));

  let status: AvatarStatus = "idle";
  if (state.src === src) {
    status = state.status;
  } else if (src) {
    status = "loading";
  }

  useEffect(() => {
    setState((current) =>
      current.src === src ? current : { src, status: src ? "loading" : "idle" },
    );
  }, [src]);

  useEffect(() => {
    if (!src) return;

    let active = true;
    const image = new Image();
    const markLoaded = () => {
      if (!active || image.naturalWidth === 0) return;
      setState({ src, status: "loaded" });
    };
    const markErrored = () => {
      if (active) setState({ src, status: "error" });
    };

    image.addEventListener("load", markLoaded);
    image.addEventListener("error", markErrored);
    image.src = src;
    if (image.complete) markLoaded();

    return () => {
      active = false;
      image.removeEventListener("load", markLoaded);
      image.removeEventListener("error", markErrored);
    };
  }, [src]);

  return {
    status,
    showImage: !!src && status !== "error",
    onLoad: () => setState({ src, status: "loaded" }),
    onError: () => setState({ src, status: "error" }),
  };
}
